public class ShaderExample {
    public static void main(String[] args) {
        // create a shader program and load the vertex and fragment shaders
        int program = GL20.glCreateProgram();
        loadShader(GL20.GL_VERTEX_SHADER, "vertexShader", program);
        loadShader(GL20.GL_FRAGMENT_SHADER, "fragmentShader", program);

        // get the location of a uniform variable
        String name = "myUniform";
        int loc = ShaderExample.getLoaction(name);

        // set the value of the uniform variable
        GL20.glUniform1f(loc, 1.0f);
    }

    private static void loadShader(int target, String filename, int program) {
        // create a new shader object and attach it to the program
        int shader = GL20.glCreateShader(target);
        GL20.glShaderSource(shader, readTextFile(filename));
        GL20.glCompileShader(shader);
        GL20.glAttachShader(program, shader);
    }

    private static String readTextFile(String filename) {
        // TODO: implement this method to read the contents of a text file
    }
}

